class Twitter {
private:
    long long timeStamp;
    vector<vector<pair<long long,int>>> tweets;
    vector<unordered_set<int>> following;

public:
    Twitter() {
        timeStamp = 0;
        tweets.resize(501);
        following.resize(501);
    }

    void postTweet(int userId, int tweetId) {
        tweets[userId].push_back({timeStamp++, tweetId});
    }

    vector<int> getNewsFeed(int userId) {
        struct Node {
            long long time;
            int tweetId;
            int idx;
            int uid;
            bool operator<(const Node& o) const {
                return time < o.time;
            }
        };

        priority_queue<Node> pq;

        if (!tweets[userId].empty()) {
            int idx = tweets[userId].size() - 1;
            pq.push({tweets[userId][idx].first, tweets[userId][idx].second, idx, userId});
        }

        for (int f : following[userId]) {
            if (!tweets[f].empty()) {
                int idx = tweets[f].size() - 1;
                pq.push({tweets[f][idx].first, tweets[f][idx].second, idx, f});
            }
        }

        vector<int> res;
        while (!pq.empty() && res.size() < 10) {
            auto top = pq.top(); pq.pop();
            res.push_back(top.tweetId);
            if (top.idx > 0) {
                int ni = top.idx - 1;
                pq.push({tweets[top.uid][ni].first, tweets[top.uid][ni].second, ni, top.uid});
            }
        }
        return res;
    }

    void follow(int followerId, int followeeId) {
        if (followerId != followeeId)
            following[followerId].insert(followeeId);
    }

    void unfollow(int followerId, int followeeId) {
        following[followerId].erase(followeeId);
    }
};

