class Twitter:

    def __init__(self):
        self.timeStamp = 0
        self.following = defaultdict(set)
        self.posts = defaultdict(deque)   # each: deque of (timestamp, tweetId)

    def postTweet(self, userId: int, tweetId: int) -> None:
        self.posts[userId].appendleft((self.timeStamp, tweetId))
        self.timeStamp += 1

    def getNewsFeed(self, userId: int):
        max_heap = []

        # Add up to 10 own tweets
        for i, (t, tw) in enumerate(self.posts[userId]):
            if i == 10:
                break
            heapq.heappush(max_heap, (t, tw))

        # Add up to 10 tweets from each followee
        for followee in self.following[userId]:
            for i, (t, tw) in enumerate(self.posts[followee]):
                if i == 10:
                    break
                heapq.heappush(max_heap, (t, tw))

        # Extract top 10 newest tweets
        result = []
        for _ in range(10):
            if not max_heap:
                break

            # Simulate max-heap using nlargest
            t, tweetId = heapq.nlargest(1, max_heap)[0]
            result.append(tweetId)

            # Remove this element
            max_heap.remove((t, tweetId))
            heapq.heapify(max_heap)

        return result

    def follow(self, followerId: int, followeeId: int) -> None:
        if followerId != followeeId:
            self.following[followerId].add(followeeId)

    def unfollow(self, followerId: int, followeeId: int) -> None:
        if followeeId in self.following[followerId]:
            self.following[followerId].remove(followeeId)

