static void *xmalloc(size_t s) {
    void *p = malloc(s);
    if (!p) { fprintf(stderr, "out of memory\n"); exit(1); }
    return p;
}

static void *xrealloc(void *p, size_t s) {
    void *q = realloc(p, s);
    if (!q) { fprintf(stderr, "out of memory\n"); exit(1); }
    return q;
}

Twitter* twitterCreate() {
    Twitter *tw = (Twitter*)xmalloc(sizeof(Twitter));
    tw->timeStamp = 0;
    /* initialize tweet storage pointers */
    tw->tweet_time = (long long**)xmalloc(sizeof(long long*) * MAX_USERS);
    tw->tweet_id   = (int**)xmalloc(sizeof(int*) * MAX_USERS);
    tw->following  = (int**)xmalloc(sizeof(int*) * MAX_USERS);

    for (int i = 0; i < MAX_USERS; ++i) {
        tw->tweets_count[i] = 0;
        tw->tweets_cap[i] = 0;
        tw->tweet_time[i] = NULL;
        tw->tweet_id[i] = NULL;

        tw->following_count[i] = 0;
        tw->following[i] = NULL;

        /* clear following_present row */
        memset(tw->following_present[i], 0, sizeof(tw->following_present[i]));
    }

    return tw;
}

void postTweet(Twitter* obj, int userId, int tweetId) {
    if (userId < 0 || userId >= MAX_USERS) return;

    int cnt = obj->tweets_count[userId];
    if (cnt == obj->tweets_cap[userId]) {
        int newcap = (obj->tweets_cap[userId] == 0) ? INIT_TWEET_CAP : obj->tweets_cap[userId] * 2;
        obj->tweet_time[userId] = (long long*)xrealloc(obj->tweet_time[userId], sizeof(long long) * newcap);
        obj->tweet_id[userId]   = (int*)xrealloc(obj->tweet_id[userId], sizeof(int) * newcap);
        obj->tweets_cap[userId] = newcap;
    }
    obj->tweet_time[userId][cnt] = obj->timeStamp++;
    obj->tweet_id[userId][cnt] = tweetId;
    obj->tweets_count[userId] ++;
}

void follow(Twitter* obj, int followerId, int followeeId) {
    if (followerId < 0 || followerId >= MAX_USERS) return;
    if (followeeId < 0 || followeeId >= MAX_USERS) return;
    if (followerId == followeeId) return;
    if (obj->following_present[followerId][followeeId]) return;

    int fc = obj->following_count[followerId];
    /* expand following list if needed */
    if (fc % 4 == 0) {
        int newcap = (fc == 0) ? 4 : fc + 4;
        obj->following[followerId] = (int*)xrealloc(obj->following[followerId], sizeof(int) * newcap);
    }
    obj->following[followerId][fc] = followeeId;
    obj->following_count[followerId] = fc + 1;
    obj->following_present[followerId][followeeId] = 1;
}

void unfollow(Twitter* obj, int followerId, int followeeId) {
    if (followerId < 0 || followerId >= MAX_USERS) return;
    if (followeeId < 0 || followeeId >= MAX_USERS) return;
    if (!obj->following_present[followerId][followeeId]) return;

    int fc = obj->following_count[followerId];
    int pos = -1;
    for (int i = 0; i < fc; ++i) {
        if (obj->following[followerId][i] == followeeId) { pos = i; break; }
    }
    if (pos == -1) return;
    /* move last into pos */
    obj->following[followerId][pos] = obj->following[followerId][fc - 1];
    obj->following_count[followerId] = fc - 1;
    obj->following_present[followerId][followeeId] = 0;
}

static void heap_push(Node heap[], int *hsize, Node val) {
    int i = ++(*hsize);
    heap[i] = val;
    while (i > 1) {
        int p = i >> 1;
        if (heap[p].time >= heap[i].time) break;
        Node tmp = heap[p]; heap[p] = heap[i]; heap[i] = tmp;
        i = p;
    }
}

static Node heap_pop(Node heap[], int *hsize) {
    Node top = heap[1];
    heap[1] = heap[*hsize];
    (*hsize)--;
    int i = 1;
    while (1) {
        int l = i << 1, r = l + 1, largest = i;
        if (l <= *hsize && heap[l].time > heap[largest].time) largest = l;
        if (r <= *hsize && heap[r].time > heap[largest].time) largest = r;
        if (largest == i) break;
        Node tmp = heap[i]; heap[i] = heap[largest]; heap[largest] = tmp;
        i = largest;
    }
    return top;
}

int* getNewsFeed(Twitter* obj, int userId, int *retSize) {
    static int result[MAX_FEED];
    *retSize = 0;

    Node heap[4096];
    int hsize = 0;

    /* push user's latest tweet */
    int cnt = obj->tweets_count[userId];
    if (cnt > 0) {
        int idx = cnt - 1;
        heap_push(heap, &hsize, (Node){ obj->tweet_time[userId][idx], obj->tweet_id[userId][idx], idx, userId });
    }

    /* push followees' latest tweets */
    for (int i = 0; i < obj->following_count[userId]; ++i) {
        int f = obj->following[userId][i];
        int c = obj->tweets_count[f];
        if (c > 0) {
            int idx = c - 1;
            heap_push(heap, &hsize, (Node){ obj->tweet_time[f][idx], obj->tweet_id[f][idx], idx, f });
        }
    }

    while (hsize > 0 && *retSize < MAX_FEED) {
        Node top = heap_pop(heap, &hsize);
        result[*retSize] = top.tweetId;
        (*retSize)++;
        if (top.idx > 0) {
            int ni = top.idx - 1;
            heap_push(heap, &hsize, (Node){ obj->tweet_time[top.uid][ni], obj->tweet_id[top.uid][ni], ni, top.uid });
        }
    }

    return result;
}

