class Twitter {

    private int timeStamp;
    private Map<Integer, Set<Integer>> following;
    private Map<Integer, Deque<int[]>> posts;   // {time, tweetId}

    public Twitter() {
        timeStamp = 0;
        following = new HashMap<>();
        posts = new HashMap<>();
    }

    public void postTweet(int userId, int tweetId) {
        posts.putIfAbsent(userId, new ArrayDeque<>());
        posts.get(userId).addFirst(new int[]{timeStamp++, tweetId});
    }

    public List<Integer> getNewsFeed(int userId) {
        PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> b[0] - a[0]);

        // Add up to 10 own tweets
        if (posts.containsKey(userId)) {
            int count = 0;
            for (int[] t : posts.get(userId)) {
                pq.offer(t);
                count++;
                if (count == 10) break;
            }
        }

        // Add up to 10 tweets from each followee
        if (following.containsKey(userId)) {
            for (int followee : following.get(userId)) {
                if (posts.containsKey(followee)) {
                    int count = 0;
                    for (int[] t : posts.get(followee)) {
                        pq.offer(t);
                        count++;
                        if (count == 10) break;
                    }
                }
            }
        }

        // Extract top 10 newest
        List<Integer> result = new ArrayList<>();
        int limit = 10;
        while (!pq.isEmpty() && limit-- > 0) {
            result.add(pq.poll()[1]);
        }

        return result;
    }

    public void follow(int followerId, int followeeId) {
        if (followerId == followeeId) return;
        following.putIfAbsent(followerId, new HashSet<>());
        following.get(followerId).add(followeeId);
    }

    public void unfollow(int followerId, int followeeId) {
        if (following.containsKey(followerId)) {
            following.get(followerId).remove(followeeId);
        }
    }
}

