class Twitter {
    constructor() {
        this.timeStamp = 0;
        this.following = new Map(); // userId -> Set of followees
        this.posts = new Map();     // userId -> array of [time, tweetId]
    }

    postTweet(userId, tweetId) {
        if (!this.posts.has(userId)) this.posts.set(userId, []);
        this.posts.get(userId).unshift([this.timeStamp++, tweetId]);
    }

    getNewsFeed(userId) {
        let maxHeap = [];

        const addTweets = (uid) => {
            if (!this.posts.has(uid)) return;
            const userPosts = this.posts.get(uid);
            const limit = Math.min(10, userPosts.length);
            for (let i = 0; i < limit; i++) {
                maxHeap.push(userPosts[i]);
            }
        };

        // own tweets
        addTweets(userId);

        // followees
        if (this.following.has(userId)) {
            for (const followee of this.following.get(userId)) {
                addTweets(followee);
            }
        }

        // sort by timestamp DESC
        maxHeap.sort((a, b) => b[0] - a[0]);

        // return top 10 tweetIds
        return maxHeap.slice(0, 10).map(x => x[1]);
    }

    follow(followerId, followeeId) {
        if (followerId === followeeId) return;
        if (!this.following.has(followerId)) {
            this.following.set(followerId, new Set());
        }
        this.following.get(followerId).add(followeeId);
    }

    unfollow(followerId, followeeId) {
        if (!this.following.has(followerId)) return;
        this.following.get(followerId).delete(followeeId);
    }
}
